// SellPage.tsx
'use client';

import React from 'react';
import {
  Box,
  Typography,
  Button,
  Tabs,
  Tab,
  Card,
  CardContent,
  CardActions,
  TextField,
  InputAdornment,
  Divider,
  List,
  ListItem,
  IconButton,
  Stack,
  Paper,
  Avatar,
  Chip,
  Rating,
} from '@mui/material';
import SearchIcon from '@mui/icons-material/Search';
import AddIcon from '@mui/icons-material/Add';
import RemoveIcon from '@mui/icons-material/Remove';
import LocalDiningIcon from '@mui/icons-material/LocalDining';

export default function SellPage() {
  return (
    <Box display="flex" p={3} sx={{ background: 'linear-gradient(to right, #e0f7fa, #f1f8ff)', height: '100vh' }}>
      {/* Left Menu */}
      <Box flex={2} pr={3}>
        <Typography variant="h4" fontWeight="bold" color="primary" gutterBottom>
          Grill Restaurant
        </Typography>
        <Typography variant="subtitle2" color="text.secondary">
          June 15, 2023
        </Typography>

        {/* Search */}
        <Box my={2}>
          <TextField
            fullWidth
            placeholder="Search food, category..."
            variant="outlined"
            sx={{ backgroundColor: '#ffffff', borderRadius: 2 }}
            InputProps={{
              startAdornment: (
                <InputAdornment position="start">
                  <SearchIcon />
                </InputAdornment>
              ),
            }}
          />
        </Box>

        {/* Tabs */}
        <Tabs
          value={0}
          variant="scrollable"
          scrollButtons="auto"
          sx={{ mb: 2, '& .MuiTab-root': { textTransform: 'none', fontWeight: 'bold' } }}
        >
          {['All', 'Pizza', 'Fast Food', 'Noodle', 'Dessert', 'Sea Food', 'Sushi', 'Ramen'].map((cat, i) => (
            <Tab key={i} label={cat} />
          ))}
        </Tabs>

        {/* Food Cards (No Grid) */}
        <Box display="flex" flexWrap="wrap" gap={2}>
          {[...Array(6)].map((_, i) => (
            <Card
              key={i}
              elevation={4}
              sx={{ width: 250, borderRadius: 3, overflow: 'hidden', flexShrink: 0 }}
            >
              <Box
                component="img"
                src={`https://source.unsplash.com/300x200/?food,meal,${i}`}
                alt="food"
                sx={{ width: '100%', height: 150, objectFit: 'cover' }}
              />
              <CardContent>
                <Typography fontWeight="bold" fontSize={16} mb={0.5}>
                  Onion Pizza
                </Typography>
                <Typography color="primary" fontWeight="bold">
                  $60.00
                </Typography>
                <Typography variant="body2" color="text.secondary" mb={1}>
                  With onion, cheese, olives...
                </Typography>
                <Stack direction="row" alignItems="center" spacing={1}>
                  <Rating name="read-only" value={5} size="small" readOnly />
                  <Typography variant="caption">5.0</Typography>
                </Stack>
              </CardContent>
              <CardActions sx={{ p: 2 }}>
                <Button size="small" variant="contained" fullWidth>
                  Add to Cart
                </Button>
              </CardActions>
            </Card>
          ))}
        </Box>
      </Box>

      {/* Cart */}
      <Box flex={1} component={Paper} elevation={6} p={3} borderRadius={4} sx={{ backgroundColor: '#ffffffd9', backdropFilter: 'blur(10px)' }}>
        <Typography variant="h6" fontWeight="bold" mb={1}>
          My Order
        </Typography>

        <Stack direction="row" spacing={1} mb={2}>
          {['Dine', 'Pick Up', 'Delivery'].map((type) => (
            <Chip key={type} label={type} variant="outlined" clickable />
          ))}
        </Stack>

        <Divider sx={{ my: 1 }} />

        <List>
          <ListItem
            secondaryAction={
              <Stack direction="row" spacing={1} alignItems="center">
                <IconButton><RemoveIcon /></IconButton>
                <Typography fontWeight="bold">2</Typography>
                <IconButton><AddIcon /></IconButton>
              </Stack>
            }
          >
            <Avatar variant="rounded" src="https://source.unsplash.com/40x40/?pizza" sx={{ mr: 1 }} />
            <Box>
              <Typography fontWeight="medium">Onion Pizza</Typography>
              <Typography variant="caption" color="text.secondary">Small Size</Typography>
            </Box>
          </ListItem>
        </List>

        <Divider sx={{ my: 1 }} />

        <Stack spacing={0.5}>
          <Typography>Items: $170</Typography>
          <Typography color="error">Discount: -$3</Typography>
          <Typography variant="h6" fontWeight="bold">Total: $167</Typography>
        </Stack>

        <Stack direction="row" spacing={1} mt={3}>
          <Button variant="contained" fullWidth color="primary">Cash</Button>
          <Button variant="outlined" fullWidth color="primary">e-Wallet</Button>
        </Stack>

        <Button variant="contained" fullWidth size="large" sx={{ mt: 2 }} endIcon={<LocalDiningIcon />}>
          Checkout
        </Button>
      </Box>
    </Box>
  );
}